package eu.gridverse.infra.config;
import com.fasterxml.jackson.databind.ObjectMapper; import eu.gridverse.infra.event.*; import eu.gridverse.infra.event.rabbitmq.*; import eu.gridverse.infra.storage.document.*; import eu.gridverse.infra.storage.document.elasticsearch.*; import eu.gridverse.infra.storage.object.*; import eu.gridverse.infra.storage.object.minio.*; import io.minio.MinioClient; import org.springframework.amqp.rabbit.connection.CachingConnectionFactory; import org.springframework.amqp.rabbit.core.RabbitTemplate; import org.springframework.beans.factory.annotation.Value; import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty; import org.springframework.context.annotation.*;
@Configuration public class InfrastructureAdapterConfiguration {
    @Bean @ConditionalOnProperty("gridverse.storage.object-endpoint") ObjectStorageService minioObjectStorage(@Value("${gridverse.storage.object-endpoint}")String endpoint,@Value("${gridverse.storage.object-access-key:gridverse}")String access,@Value("${gridverse.storage.object-secret-key:gridverse-local-secret}")String secret){return new MinioObjectStorageService(MinioClient.builder().endpoint(endpoint).credentials(access,secret).build());}
    @Bean @ConditionalOnProperty("gridverse.storage.document-endpoint") DocumentRepositoryService elasticsearchDocuments(@Value("${gridverse.storage.document-endpoint}")String endpoint,ObjectMapper json){return new ElasticsearchDocumentRepository(endpoint,json);}
    @Bean @ConditionalOnProperty("gridverse.messaging.rabbitmq-host") EventPublisherService rabbitEvents(@Value("${gridverse.messaging.rabbitmq-host}")String host,ObjectMapper json){CachingConnectionFactory connection=new CachingConnectionFactory(host);RabbitTemplate template=new RabbitTemplate(connection);template.setMessageConverter(new org.springframework.amqp.support.converter.Jackson2JsonMessageConverter(json));return new RabbitMqEventPublisher(template);}
}
